export enum Platform {
  LINKEDIN = 'LinkedIn',
  TWITTER = 'Twitter'
}

export interface GeneratedContent {
  postText: string;
  imagePrompt: string;
}

export interface GenerationResult {
  content: GeneratedContent | null;
  imageUrl: string | null;
  isLoading: boolean;
  error: string | null;
}

export enum GenerationStep {
  IDLE = 'IDLE',
  GENERATING_TEXT = 'GENERATING_TEXT',
  GENERATING_IMAGE = 'GENERATING_IMAGE',
  COMPLETED = 'COMPLETED',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type } from "@google/genai";
import { GeneratedContent, Platform } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

/**
 * Generates the text content and an image prompt based on the news input.
 */
export const generateHealthTechContent = async (
  newsInput: string, 
  platform: Platform
): Promise<GeneratedContent> => {
  if (!apiKey) throw new Error("API Key is missing.");

  const model = "gemini-3-flash-preview";

  const platformContext = platform === Platform.LINKEDIN 
    ? "Professional, insightful, slightly longer form (150-250 words), focusing on industry impact, career implications, and strategic analysis. Use professional hashtags."
    : "Concise, punchy, engaging, threaded-style (limit to 280 chars per tweet idea, but provide a coherent short thread or single strong tweet), focusing on breaking news and immediate relevance. Use trending hashtags.";

  const systemInstruction = `
    You are a world-class Health Tech Expert and Thought Leader. 
    Your mission is to interpret general or specific healthcare news and explain why it matters for the future of medicine, digital health, and patient outcomes.

    Tone: Captivating, authoritative, optimistic yet grounded, professional.
    Context: ${platformContext}

    You must also generate a detailed prompt for a realistic, high-quality illustrative image that visually represents the core theme of the news in a modern healthcare setting. The image prompt should describe lighting, composition, and key elements (e.g., doctors using tablets, holographic data, futuristic medical devices in a warm clinical setting).
  `;

  const prompt = `
    Analyze this news snippet and generate a post and an image prompt:
    "${newsInput}"
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          postText: {
            type: Type.STRING,
            description: "The formatted social media post content.",
          },
          imagePrompt: {
            type: Type.STRING,
            description: "A detailed description for generating a realistic illustrative image.",
          },
        },
        required: ["postText", "imagePrompt"],
      },
    },
  });

  const text = response.text;
  if (!text) throw new Error("Failed to generate text content.");

  try {
    return JSON.parse(text) as GeneratedContent;
  } catch (e) {
    console.error("Failed to parse JSON response", e);
    throw new Error("Invalid response format from AI.");
  }
};

/**
 * Generates an image based on the prompt provided by the text model.
 */
export const generateIllustrativeImage = async (imagePrompt: string): Promise<string> => {
  if (!apiKey) throw new Error("API Key is missing.");

  // Using gemini-2.5-flash-image for image generation as per guidelines for general image tasks
  const model = "gemini-2.5-flash-image";

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { text: imagePrompt + " Photorealistic, cinematic lighting, 8k resolution, highly detailed, professional photography style." }
      ]
    },
    config: {
      // Using a square aspect ratio for social media versatility
      imageConfig: {
        aspectRatio: "1:1" 
      }
    }
  });

  // Extract image from response parts
  // The response might contain text and inlineData. We need the inlineData.
  const candidates = response.candidates;
  if (!candidates || candidates.length === 0) {
    throw new Error("No image candidates returned.");
  }

  const parts = candidates[0].content.parts;
  let base64Image = "";
  let mimeType = "";

  for (const part of parts) {
    if (part.inlineData) {
      base64Image = part.inlineData.data;
      mimeType = part.inlineData.mimeType;
      break; 
    }
  }

  if (!base64Image) {
    throw new Error("No image data found in response.");
  }

  return `data:${mimeType};base64,${base64Image}`;
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading = false, 
  className = '', 
  disabled,
  ...props 
}) => {
  const baseStyles = "px-4 py-2 rounded-lg font-medium transition-all duration-200 flex items-center justify-center gap-2 focus:outline-none focus:ring-2 focus:ring-offset-1 disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-teal-600 hover:bg-teal-700 text-white focus:ring-teal-500 shadow-md",
    secondary: "bg-slate-800 hover:bg-slate-900 text-white focus:ring-slate-500 shadow-md",
    outline: "border-2 border-slate-200 hover:border-teal-500 hover:text-teal-600 text-slate-600 bg-transparent"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${className}`}
      disabled={disabled || isLoading}
      {...props}
    >
      {isLoading && (
        <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
