import React, { useState } from 'react';
import { InputSection } from './components/InputSection';
import { ResultCard } from './components/ResultCard';
import { GenerationResult, Platform, GenerationStep } from './types';
import { generateHealthTechContent, generateIllustrativeImage } from './services/geminiService';

const App: React.FC = () => {
  const [result, setResult] = useState<GenerationResult>({
    content: null,
    imageUrl: null,
    isLoading: false,
    error: null,
  });
  const [step, setStep] = useState<GenerationStep>(GenerationStep.IDLE);

  const handleGenerate = async (news: string, platform: Platform) => {
    setResult({ content: null, imageUrl: null, isLoading: true, error: null });
    setStep(GenerationStep.GENERATING_TEXT);

    try {
      // Step 1: Generate Text and Image Prompt
      const generatedContent = await generateHealthTechContent(news, platform);

      setResult(prev => ({
        ...prev,
        content: generatedContent,
      }));

      setStep(GenerationStep.GENERATING_IMAGE);

      // Step 2: Generate Image
      const imageUrl = await generateIllustrativeImage(generatedContent.imagePrompt);

      setResult(prev => ({
        ...prev,
        imageUrl,
        isLoading: false,
      }));
      setStep(GenerationStep.COMPLETED);

    } catch (error: any) {
      console.error("Generation failed:", error);
      setResult(prev => ({
        ...prev,
        isLoading: false,
        error: error.message || "An unexpected error occurred. Please try again.",
      }));
      setStep(GenerationStep.ERROR);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 selection:bg-teal-100 selection:text-teal-900">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 rounded-lg bg-teal-600 flex items-center justify-center text-white font-bold text-lg">
              H
            </div>
            <h1 className="text-xl font-bold bg-gradient-to-r from-teal-700 to-teal-500 bg-clip-text text-transparent">
              HealthTech Pulse
            </h1>
          </div>
          <div className="text-xs font-medium text-slate-500 bg-slate-100 px-3 py-1 rounded-full border border-slate-200">
            Powered by Gemini 2.5 & 3.0
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 py-8 md:py-12">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 items-start">

          {/* Left Column: Input */}
          <div className="lg:sticky lg:top-24">
            <div className="mb-6">
              <h1 className="text-3xl md:text-4xl font-extrabold text-slate-900 tracking-tight mb-4">
                Transform News into <br/>
                <span className="text-teal-600">Expert Insight</span>
              </h1>
              <p className="text-lg text-slate-600 leading-relaxed">
                Create engaging, professional commentary for social media backed by realistic AI-generated illustrations. Perfect for Health Tech thought leadership.
              </p>
            </div>
            <InputSection 
              onGenerate={handleGenerate} 
              isGenerating={result.isLoading} 
            />

             <div className="mt-8 text-center text-xs text-slate-400">
                <p>Generates text using <strong>Gemini 3 Flash</strong> and visuals using <strong>Gemini 2.5 Flash Image</strong>.</p>
             </div>
          </div>

          {/* Right Column: Output */}
          <div className="h-full min-h-[500px]">
            <ResultCard result={result} />
          </div>

        </div>
      </main>
    </div>
  );
};

export default App;

