import { GoogleGenAI, Type } from "@google/genai";
import { GeneratedContent, Platform, TrendsResult, TrendItem, Source } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

/**
 * Generates the text content and an image prompt based on the news input.
 */
export const generateHealthTechContent = async (
  newsInput: string, 
  platform: Platform
): Promise<GeneratedContent> => {
  if (!apiKey) throw new Error("API Key is missing.");

  const model = "gemini-3-flash-preview";

  const platformContext = platform === Platform.LINKEDIN 
    ? "Conversational, storytelling style (150-250 words). Start with a relatable hook. **Crucially, weave in specific data points, statistics, percentages, or concrete examples from the provided text to anchor your insight.** Focus on the 'why this matters' in simple, human terms but back it up with the facts provided. Use engaging formatting (bullet points, line breaks). Make it feel like a passionate insight shared by a knowledgeable friend. End with a question."
    : "High-energy, exciting, and viral-ready. **Use a specific number, percentage, or fact from the text as a hook.** Use punchy sentences, questions, and emojis. Focus on the 'wow' factor supported by evidence from the source. Keep it concise (under 280 chars/tweet) but impactful.";

  const systemInstruction = `
    You are an enthusiastic Health Tech Innovator and Influencer. 
    Your mission is to take healthcare news and turn it into exciting, relatable content that gets people talking.

    Tone: Conversational, relatable, high-energy, optimistic, and accessible. Avoid stiff corporate jargon. Speak directly to the reader ("you", "we").
    Context: ${platformContext}

    **Instruction on Evidence:**
    You must extract and include specific examples, data, percentages, or numbers from the source material to add credibility. Do not just speak in generalities; use the details provided in the input to make the content concrete.

    You must also generate a detailed prompt for a realistic, high-quality illustrative image that visually represents the core theme of the news in a modern healthcare setting. The image prompt should describe lighting, composition, and key elements (e.g., doctors using tablets, holographic data, futuristic medical devices in a warm clinical setting).
  `;

  const prompt = `
    Analyze this news snippet and generate a post and an image prompt.
    Look for specific data, numbers, and examples in the text and include them in the post to prove the point:
    "${newsInput}"
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          postText: {
            type: Type.STRING,
            description: "The formatted social media post content.",
          },
          imagePrompt: {
            type: Type.STRING,
            description: "A detailed description for generating a realistic illustrative image.",
          },
        },
        required: ["postText", "imagePrompt"],
      },
    },
  });

  const text = response.text;
  if (!text) throw new Error("Failed to generate text content.");

  try {
    return JSON.parse(text) as GeneratedContent;
  } catch (e) {
    console.error("Failed to parse JSON response", e);
    throw new Error("Invalid response format from AI.");
  }
};

/**
 * Generates an image based on the prompt provided by the text model.
 */
export const generateIllustrativeImage = async (imagePrompt: string): Promise<string> => {
  if (!apiKey) throw new Error("API Key is missing.");

  // Using gemini-2.5-flash-image for image generation as per guidelines for general image tasks
  const model = "gemini-2.5-flash-image";

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { text: imagePrompt + " Photorealistic, cinematic lighting, vibrant and engaging, 8k resolution, highly detailed, professional photography style." }
      ]
    },
    config: {
      // Using a square aspect ratio for social media versatility
      imageConfig: {
        aspectRatio: "1:1" 
      }
    }
  });

  // Extract image from response parts
  // The response might contain text and inlineData. We need the inlineData.
  const candidates = response.candidates;
  if (!candidates || candidates.length === 0) {
    throw new Error("No image candidates returned.");
  }

  const parts = candidates[0].content.parts;
  let base64Image = "";
  let mimeType = "";

  for (const part of parts) {
    if (part.inlineData) {
      base64Image = part.inlineData.data;
      mimeType = part.inlineData.mimeType;
      break; 
    }
  }

  if (!base64Image) {
    throw new Error("No image data found in response.");
  }

  return `data:${mimeType};base64,${base64Image}`;
};

/**
 * Scans for trending health tech news using Google Search grounding.
 */
export const getTrendingNews = async (): Promise<TrendsResult> => {
  if (!apiKey) throw new Error("API Key is missing.");

  const model = "gemini-3-flash-preview";

  // Prompt asks for a specific format to facilitate parsing since JSON response is not guaranteed with Search Grounding
  const prompt = `
    Find 3 distinct, high-impact and exciting news stories in Health Technology, Digital Health, or AI in Medicine from the last 48 hours.

    For each story, provide a Catchy Headline and a 1-sentence Intriguing Summary that makes people want to read more.

    Strictly format your response as follows for each item:

    ITEM_START
    HEADLINE: [Insert Headline Here]
    SUMMARY: [Insert Summary Here]
    ITEM_END
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
    },
  });

  const text = response.text || "";

  // Parse the text based on the requested format
  const trends: TrendItem[] = [];
  const items = text.split("ITEM_START");

  for (const item of items) {
    const headlineMatch = item.match(/HEADLINE:\s*(.+)/);
    const summaryMatch = item.match(/SUMMARY:\s*(.+)/); // Simple regex, assumes summary is on one line or rest of block

    if (headlineMatch && summaryMatch) {
      // Clean up the summary by removing ITEM_END if it was captured
      let summary = summaryMatch[1].trim();
      if (summary.includes("ITEM_END")) {
        summary = summary.split("ITEM_END")[0].trim();
      }

      trends.push({
        headline: headlineMatch[1].trim(),
        summary: summary,
      });
    }
  }

  // Extract sources from grounding chunks
  const sources: Source[] = [];
  const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

  if (groundingChunks) {
    groundingChunks.forEach((chunk: any) => {
      if (chunk.web) {
        sources.push({
          title: chunk.web.title || "Source",
          uri: chunk.web.uri
        });
      }
    });
  }

  // Deduplicate sources based on URI
  const uniqueSources = sources.filter((v, i, a) => a.findIndex(t => (t.uri === v.uri)) === i);

  return {
    trends: trends.slice(0, 3), // Ensure we only return up to 3
    sources: uniqueSources
  };
};

