        {/* Scheduling Section */}
        {content && imageUrl && !isLoading && (
          <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 mt-6">
            <label className="text-sm font-semibold text-slate-700 mb-2 block flex items-center gap-2">
