        )}

        {/* Empty State */}
        {!isLoading && !content && !error && (
            <div className="h-64 flex flex-col items-center justify-center text-slate-400">
                <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1" strokeLinecap="round" strokeLinejoin="round" className="mb-4 text-slate-300"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V7.5L14 2z"/><polyline points="14 2 14 8 20 8"/><line x1="12" y1="18" x2="12" y2="12"/><line x1="9" y1="15" x2="15" y2="15"/></svg>
                <p>Your generated content will appear here</p>
            </div>
        )}
      </div>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { GeneratedContent, Platform, TrendsResult, TrendItem, Source } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

/**
 * Generates the text content and a search query for an image based on the news input.
 */
export const generateHealthTechContent = async (
  newsInput: string, 
  platform: Platform
): Promise<GeneratedContent> => {
  if (!apiKey) throw new Error("API Key is missing.");

  const model = "gemini-3-flash-preview";

  const platformContext = platform === Platform.LINKEDIN 
    ? "Write a visionary, thought-provoking post (150-250 words). Start with a hook about how science fiction is becoming reality or a shift in the medical paradigm. **Use bullet points to clearly list the key implications, benefits, or data points.** Focus on digital health transformation, patient empowerment, and the human side of technology. **Do NOT use hashtags.** End with a question about the future of this technology."
    : "Write a short, punchy, and visionary insight. Focus on the immediate future impact. **Use a brief bulleted list if it helps clarity.** **Do NOT use hashtags.** Keep it under 280 characters.";

  const systemInstruction = `
    You are **The Medical Futurist** (inspired by the style of Bertalan Meskó).
    Your mission is to analyze health technology news and explain why it matters for the future of medicine and the patient-doctor relationship.

    **Tone & Style:**
    - Visionary, optimistic, and energetic.
    - Accessible yet authoritative.
    - Bridge the gap between science fiction and reality.
    - Focus on "cultural transformation" in healthcare, not just the tech.
    - **ALWAYS use bullet points** to structure the main arguments or data points for readability and impact.
    - **NEVER use hashtags.**

    Context: ${platformContext}

    **Instruction on Evidence:**
    You must extract and include specific examples, data, percentages, or numbers from the source material to anchor your visionary claims in reality.

    **Instruction on Image:**
    Instead of describing an AI image, provide a specific **Search Query** to find a real-world image related to this news (e.g., "Da Vinci surgical robot operation", "modern digital pathology lab", "doctor using handheld ultrasound").
  `;

  const prompt = `
    Analyze this news snippet as The Medical Futurist and generate a post and a search query for an image.
    Look for specific data, numbers, and examples in the text and include them in the post to anchor the insight:
    "${newsInput}"
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          postText: {
            type: Type.STRING,
            description: "The formatted social media post content.",
          },
          imagePrompt: {
            type: Type.STRING,
            description: "A specific search query to find an existing real-world image on the web.",
          },
        },
        required: ["postText", "imagePrompt"],
      },
    },
  });

  const text = response.text;
  if (!text) throw new Error("Failed to generate text content.");

  try {
    return JSON.parse(text) as GeneratedContent;
  } catch (e) {
    console.error("Failed to parse JSON response", e);
    throw new Error("Invalid response format from AI.");
  }
};

/**
 * Rewrites the text to sound more natural and human-like.
 */
export const naturalizeText = async (text: string, platform: Platform): Promise<string> => {
  if (!apiKey) throw new Error("API Key is missing.");
  const model = "gemini-3-flash-preview";

  const prompt = `
    Rewrite the following social media post to sound more natural, human-written, and conversational.
    Remove robotic phrasing, excessive buzzwords, or stiff sentence structures.
    Keep the core message, facts, and data points exactly as they are.
    Keep the formatting (bullet points, etc.) appropriate for ${platform}.
    Do NOT use hashtags.

    Original Text:
    "${text}"
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
  });

  return response.text?.trim() || text;
};

/**
 * Finds a related image URL from the internet using Google Search grounding.
 */
export const findRelatedImage = async (searchQuery: string): Promise<string> => {
  if (!apiKey) throw new Error("API Key is missing.");

  const model = "gemini-3-flash-preview";

  const prompt = `
    Find a publicly accessible, high-quality image URL related to the following topic: "${searchQuery}".
    The image should be suitable for a professional healthcare presentation.

    Return ONLY the raw URL string of the image. Do not return Markdown or JSON.
    If you find a news article with a relevant image, extract the image URL.
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
    },
  });

  let imageUrl = response.text?.trim() || "";

  // Basic cleanup if the model returns markdown like ![](url) or [link](url)
  const markdownMatch = imageUrl.match(/\((https?:\/\/[^)]+)\)/);
  if (markdownMatch) {
    imageUrl = markdownMatch[1];
  }

  // If the model fails to return a valid URL structure, return a placeholder or empty string
  if (!imageUrl.startsWith("http")) {
      // Fallback: If we can't get a direct URL, we might want to return null or handle it in UI
      // For now, let's try to see if grounding chunks have any image assets (rare for text search but possible)
      // or just return empty so the UI shows a placeholder.
      console.warn("Model did not return a valid image URL:", imageUrl);
      return "";
  }

  return imageUrl;
};

/**
 * Scans for trending health tech news using Google Search grounding.
 */
export const getTrendingNews = async (): Promise<TrendsResult> => {
  if (!apiKey) throw new Error("API Key is missing.");

  const model = "gemini-3-flash-preview";

  // Prompt asks for a specific format to facilitate parsing since JSON response is not guaranteed with Search Grounding
  const prompt = `
    Find 3 distinct, high-impact news stories in Health Technology, Digital Health, or AI in Medicine from the last 48 hours that would be relevant to healthcare professionals.

    For each story, provide a Professional Headline and a 1-sentence Strategic Summary.

    Strictly format your response as follows for each item:

    ITEM_START
    HEADLINE: [Insert Headline Here]
    SUMMARY: [Insert Summary Here]
    ITEM_END
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
    },
  });

  const text = response.text || "";

  // Parse the text based on the requested format
  const trends: TrendItem[] = [];
  const items = text.split("ITEM_START");

  for (const item of items) {
    const headlineMatch = item.match(/HEADLINE:\s*(.+)/);
    const summaryMatch = item.match(/SUMMARY:\s*(.+)/); // Simple regex, assumes summary is on one line or rest of block

    if (headlineMatch && summaryMatch) {
      // Clean up the summary by removing ITEM_END if it was captured
      let summary = summaryMatch[1].trim();
      if (summary.includes("ITEM_END")) {
        summary = summary.split("ITEM_END")[0].trim();
      }

      trends.push({
        headline: headlineMatch[1].trim(),
        summary: summary,
      });
    }
  }

  // Extract sources from grounding chunks
  const sources: Source[] = [];
  const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

  if (groundingChunks) {
    groundingChunks.forEach((chunk: any) => {
      if (chunk.web) {
        sources.push({
          title: chunk.web.title || "Source",
          uri: chunk.web.uri
        });
      }
    });
  }

  // Deduplicate sources based on URI
  const uniqueSources = sources.filter((v, i, a) => a.findIndex(t => (t.uri === v.uri)) === i);

  return {
    trends: trends.slice(0, 3), // Ensure we only return up to 3
    sources: uniqueSources
  };
};

import React, { useState, useEffect, useRef } from 'react';
import { GenerationResult, Platform } from '../types';
import { Button } from './Button';
import { toSocialBold, toSocialItalic, HEALTHCARE_EMOJIS } from '../utils/textFormatting';
import { naturalizeText } from '../services/geminiService';

interface ResultCardProps {
  result: GenerationResult;
  currentPlatform: Platform;
  onSchedule: (date: string, contentText: string) => void;
}

export const ResultCard: React.FC<ResultCardProps> = ({ result, currentPlatform, onSchedule }) => {
  const { content, imageUrl, isLoading, error } = result;
  const [scheduleDate, setScheduleDate] = useState('');
  const [editedText, setEditedText] = useState('');
  const [imageError, setImageError] = useState(false);
  const [isNaturalizing, setIsNaturalizing] = useState(false);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  // Sync editedText when new content is generated
  useEffect(() => {
    if (content?.postText) {
      setEditedText(content.postText);
    }
  }, [content]);

  // Reset image error when new image URL arrives
  useEffect(() => {
    setImageError(false);
  }, [imageUrl]);

  const handleCopy = () => {
    if (editedText) {
      navigator.clipboard.writeText(editedText);
      alert('Content copied to clipboard!');
    }
  };

  const handleNaturalize = async () => {
    if (!editedText) return;
    setIsNaturalizing(true);
    try {
      const naturalized = await naturalizeText(editedText, currentPlatform);
      setEditedText(naturalized);
    } catch (err) {
      console.error("Failed to naturalize text", err);
      alert("Failed to naturalize text. Please try again.");
    } finally {
      setIsNaturalizing(false);
    }
  };

  const downloadImage = () => {
    if (imageUrl) {
      const link = document.createElement('a');
      link.href = imageUrl;
      link.download = 'related-image.jpg';
      link.target = "_blank"; // Open in new tab if download is blocked by CORS
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
  };

  const handleScheduleClick = () => {
    if (!scheduleDate || !editedText) return;
    onSchedule(scheduleDate, editedText);
    setScheduleDate('');
  };

  const applyFormatting = (formatFn: (s: string) => string) => {
    const textarea = textareaRef.current;
    if (!textarea) return;

    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;
    const text = editedText;

    if (start === end) return; // No selection

    const before = text.substring(0, start);
    const selection = text.substring(start, end);
    const after = text.substring(end);

    const formattedSelection = formatFn(selection);
    const newText = before + formattedSelection + after;

    setEditedText(newText);

    // Restore selection / focus needs a small timeout or re-render handling
    setTimeout(() => {
        textarea.focus();
        textarea.setSelectionRange(start, start + formattedSelection.length);
    }, 0);
  };

  const insertAtCursor = (insertion: string) => {
    const textarea = textareaRef.current;
    if (!textarea) return;

    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;
    const text = editedText;

    const newText = text.substring(0, start) + insertion + text.substring(end);
    setEditedText(newText);

    setTimeout(() => {
        textarea.focus();
        textarea.setSelectionRange(start + insertion.length, start + insertion.length);
    }, 0);
  };

  const toggleBulletList = () => {
      const textarea = textareaRef.current;
      if (!textarea) return;

      const start = textarea.selectionStart;
      const end = textarea.selectionEnd;
      const text = editedText;

      // Find start of line for selection start
      let lineStart = text.lastIndexOf('\n', start - 1) + 1;

      // Find end of line for selection end
      let lineEnd = text.indexOf('\n', end);
      if (lineEnd === -1) lineEnd = text.length;

      const selectedBlock = text.substring(lineStart, lineEnd);
      const lines = selectedBlock.split('\n');

      const newLines = lines.map(line => {
          if (line.trim().startsWith('• ')) {
              return line.replace('• ', '');
          } else {
              return `• ${line}`;
          }
      });

      const newBlock = newLines.join('\n');
      const newText = text.substring(0, lineStart) + newBlock + text.substring(lineEnd);

      setEditedText(newText);
      setTimeout(() => {
        textarea.focus();
        textarea.setSelectionRange(lineStart, lineStart + newBlock.length);
      }, 0);
  };

  if (!content && !isLoading && !error) return null;

  return (
    <div className="bg-white rounded-b-2xl shadow-none flex flex-col h-full">
      <div className="p-6 md:p-8 flex-1 space-y-8 overflow-y-auto">
        {error && (
          <div className="p-4 rounded-lg bg-red-50 text-red-600 border border-red-100">
            <strong>Error:</strong> {error}
          </div>
        )}

        {/* Text Content Section */}
        {content && (
          <div className="space-y-4 animate-fade-in">
            <div className="flex justify-between items-end">
              <label className="text-sm font-semibold text-slate-500 uppercase tracking-wider">Post Editor</label>
              <div className="flex gap-2">
                 <Button 
                    variant="outline" 
                    onClick={handleNaturalize} 
                    className="text-xs py-1 px-3 text-teal-600 border-teal-200 hover:bg-teal-50"
                    disabled={isNaturalizing}
                 >
                    {isNaturalizing ? (
                        <>
                           <svg className="animate-spin -ml-1 mr-1 h-3 w-3 text-teal-600" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                           Refining...
                        </>
                    ) : (
                        <>
                           <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="mr-1"><path d="M21 11.5a8.38 8.38 0 0 1-.9 3.8 8.5 8.5 0 0 1-7.6 4.7 8.38 8.38 0 0 1-3.8-.9L3 21l1.9-5.7a8.38 8.38 0 0 1-.9-3.8 8.5 8.5 0 0 1 4.7-7.6 8.38 8.38 0 0 1 3.8-.9h.5a8.48 8.48 0 0 1 8 8v.5z"></path></svg>
                           Naturalize
                        </>
                    )}
                 </Button>
                 <Button variant="outline" onClick={handleCopy} className="text-xs py-1 px-3">
                    <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="mr-1"><rect x="9" y="9" width="13" height="13" rx="2" ry="2"></rect><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"></path></svg>
                    Copy Text
